const row = $input.first().json;

const stdout = row.stdout || "";
const stderr = row.stderr || "";
const exitCode = row.exitCode ?? null;

function matchOne(pattern, text) {
  const m = text.match(pattern);
  return m ? m[1] : null;
}

function countMatches(pattern, text) {
  const matches = text.match(pattern);
  return matches ? matches.length : 0;
}

const insertedDeals = matchOne(/Inserted new deals:\s*(\d+)/, stdout);
const skippedDeals = matchOne(/Skipped existing deals:\s*(\d+)/, stdout);
const dealsToEnrich = matchOne(/Found\s+(\d+)\s+deals to enrich/, stdout);
const dealsToSync = matchOne(/Found\s+(\d+)\s+deal\(s\) to sync\./, stdout);
const syncedDeals = countMatches(/\[SYNCED\]/g, stdout);
const failedDeals = countMatches(/\[FAILED\]/g, stdout);
const syncedNone = /No eligible deals ready for Notion sync\./.test(stdout);
const pipelineComplete = /PIPELINE COMPLETE/.test(stdout);

const failed = exitCode !== 0 || !!stderr;

return [
  {
    json: {
      status: failed ? "failed" : "success",
      exitCode,
      insertedDeals: insertedDeals ? Number(insertedDeals) : null,
      skippedDeals: skippedDeals ? Number(skippedDeals) : null,
      dealsToEnrich: dealsToEnrich ? Number(dealsToEnrich) : null,
      dealsToSync: dealsToSync ? Number(dealsToSync) : 0,
      syncedDeals,
      failedDeals,
      notionResult: syncedNone ? "No eligible deals for Notion sync" : `Synced ${syncedDeals} deal(s), failed ${failedDeals}`,
      pipelineComplete,
      shortSummary: failed
        ? `Pipeline failed. Synced ${syncedDeals} deal(s), failed ${failedDeals}. Check stderr/raw logs.`
        : `Pipeline succeeded. Inserted ${insertedDeals ?? 0} new deals, skipped ${skippedDeals ?? 0}, enriched ${dealsToEnrich ?? 0}, synced ${syncedDeals}, failed ${failedDeals}.`,
      rawStdout: stdout,
      rawStderr: stderr,
    },
  },
];
